import React, { useState, useEffect, useRef } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = ({ markDayComplete }) => {
  const { day } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();

  // 1. SESSION CONFIG (45 Minutes)
  const [timeLeft, setTimeLeft] = useState(3); 
  const [isActive, setIsActive] = useState(false);
  const [sessionFinished, setSessionFinished] = useState(false);
  const [tabWarning, setTabWarning] = useState(false);
  const [userAnswer, setUserAnswer] = useState('');
  
  const videoRef = useRef(null);
  const streamRef = useRef(null);

  // 2. CAMERA & CLEANUP (Warning-Free Logic)
  useEffect(() => {
    const currentVideoElement = videoRef.current;
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
        streamRef.current = stream;
        if (currentVideoElement) {
          currentVideoElement.srcObject = stream;
        }
      } catch (err) {
        console.error("Camera access denied:", err);
      }
    }
    startCamera();

    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
      }
      if (currentVideoElement) {
        currentVideoElement.srcObject = null;
      }
    };
  }, []);

  // 3. TAB PROTECTION: Pause timer if student switches tabs
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden) {
        setIsActive(false);
        setTabWarning(true);
      } else {
        setTabWarning(false);
      }
    };
    document.addEventListener("visibilitychange", handleVisibilityChange);
    return () => document.removeEventListener("visibilitychange", handleVisibilityChange);
  }, []);

  // 4. THE MASTER TIMER: Unlocks verification at 00:00
  useEffect(() => {
    let interval = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0) {
      setSessionFinished(true); // <--- THIS UNLOCKS THE UI
      setIsActive(false);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}m ${secs < 10 ? '0' : ''}${secs}s`;
  };

  const handleFinalSubmit = () => {
    // Verification check: ensure they actually wrote something meaningful
    if (userAnswer.trim().length < 50) {
      alert("Verification Failed: Your summary is too short. Please explain your practice in detail (minimum 50 characters).");
      return;
    }
    markDayComplete(day); // Updates Dashboard status to Green
    navigate('/dashboard');
  };

  return (
    <div style={{ padding: '20px', textAlign: 'center', backgroundColor: '#f4f7f6', minHeight: '100vh', fontFamily: 'Arial' }}>
      <div style={{ maxWidth: '700px', margin: '0 auto', background: 'white', padding: '35px', borderRadius: '25px', boxShadow: '0 15px 35px rgba(0,0,0,0.1)' }}>
        
        <h2 style={{ color: '#2c3e50' }}>Study Session: Day {day}</h2>
        <p style={{ color: '#3498db', fontWeight: 'bold', letterSpacing: '1px' }}>TOPIC: {state?.topic?.toUpperCase() || "FOCUS MODE"}</p>

        {/* PROCTORING CAM */}
        <div style={{ position: 'relative', width: '380px', height: '280px', margin: '20px auto', backgroundColor: '#2c3e50', borderRadius: '15px', overflow: 'hidden', border: '6px solid #ecf0f1', boxShadow: 'inset 0 0 10px #000' }}>
          <video ref={videoRef} autoPlay playsInline muted style={{ width: '100%', height: '100%', objectFit: 'cover', transform: 'scaleX(-1)' }} />
          {!isActive && !sessionFinished && (
            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.6)', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '18px' }}>
              ⏸ FOCUS PAUSED
            </div>
          )}
        </div>

        {tabWarning && (
          <div style={{ color: 'white', background: '#e74c3c', padding: '12px', borderRadius: '10px', marginBottom: '20px', fontWeight: 'bold', animation: 'shake 0.5s' }}>
            🚫 TAB SWITCH DETECTED! Timer stopped. Stay on this page.
          </div>
        )}

        <div style={{ fontSize: '75px', fontWeight: '900', color: timeLeft === 0 ? '#27ae60' : '#2c3e50', margin: '25px 0' }}>
          {formatTime(timeLeft)}
        </div>

        {/* PHASE 1: STUDYING (Button is visible, Verification is hidden) */}
        {!sessionFinished ? (
          <div>
            <p style={{ color: '#7f8c8d', marginBottom: '20px' }}>Verification field will unlock automatically when timer ends.</p>
            <button 
              onClick={() => setIsActive(!isActive)}
              style={{ padding: '18px 60px', fontSize: '20px', background: isActive ? '#f39c12' : '#2ecc71', color: 'white', border: 'none', borderRadius: '50px', cursor: 'pointer', transition: '0.3s', fontWeight: 'bold', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}
            >
              {isActive ? 'PAUSE STUDY' : 'START FOCUS NOW'}
            </button>
          </div>
        ) : (
          /* PHASE 2: VERIFICATION (Unlocked only when timeLeft === 0) */
          <div style={{ marginTop: '20px', textAlign: 'left', padding: '20px', backgroundColor: '#e8f6f3', borderRadius: '15px', border: '2px solid #27ae60' }}>
            <h3 style={{ color: '#27ae60', marginTop: 0 }}>✓ Time Complete!</h3>
            <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '10px' }}>AI Verification Question:</label>
            <p style={{ fontSize: '14px', color: '#34495e', marginBottom: '15px' }}>
              Based on your 45-minute practice of <strong>{state?.topic}</strong>, what was the most complex part you encountered and how did you resolve it?
            </p>
            
            <textarea 
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              placeholder="Provide a detailed answer (Min. 50 characters)..."
              style={{ width: '100%', height: '120px', padding: '12px', borderRadius: '10px', border: '1px solid #bdc3c7', marginBottom: '15px', fontSize: '15px', boxSizing: 'border-box' }}
            />

            <button 
              onClick={handleFinalSubmit}
              style={{ width: '100%', padding: '18px', background: '#2c3e50', color: 'white', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold', border: 'none', fontSize: '16px' }}
            >
              VERIFY & MARK AS COMPLETED
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudySession;
